///<reference path="./Variable.d.ts"/>

import { DOMEventsAsync, DoEvents } from "./util";

export abstract class LoadManager {

    static async Init() {
        window.addEventListener("load", () => console.info("window.onload"));

        var timing = await DOMEventsAsync(document);
        await DoEvents();
        await timing[0];
        LoadManager.DOMContentLoaded();
        await timing[1];
        LoadManager.load();
    }


    private static DOMContentLoaded() {
        for (var item of LoadManager.Items) {
            if (!item.IsReady) {
                item.Ready();
                item._IsReady = true;
            }
        }
    }

    private static load() {
        for (var item of LoadManager.Items) {
            if (!item.IsLoaded) {
                item.Load();
                item._IsLoaded = true;
            }
        }
    }

    public static RaiseUnLoad() {
        for (var item of LoadManager.Items) {
            item.UnLoadGlobal();
            item._IsLoaded = false;
            item._IsReady = false;
        }
    }

    public static RaiseReady() {
        {//ライブラリの再起動
            //MathJax.Hub.Queue(["Typeset", MathJax.Hub]);
            Prism.highlightAll();
            //mermaid.init();
        }
        LoadManager.DOMContentLoaded();
    }

    public static RaiseLoad() {
        LoadManager.load();
    }


    protected abstract Ready();
    protected abstract Load();
    protected abstract PreUnLoad();
    protected abstract AfterUnLoad();

    private UnLoadGlobal() {
        this.PreUnLoad();
        for (var l of this.Listeners) {
            if (l[3])
                l[3](l[0]);
            l[0].removeEventListener(l[1], l[2]);
        }
        this.AfterUnLoad();
        this.Listeners = [];
    }

    protected Listeners: [HTMLElement, string, (this: HTMLElement, ev) => any, (target: HTMLElement) => void][] = [];

    protected PreUnLoadFuncs: Function[] = [];
    protected AfterUnLoadFuncs: Function[] = [];

    private _IsReady: boolean = false;
    get IsReady(): boolean { return this._IsReady; }

    private _IsLoaded: boolean = false;
    get IsLoaded(): boolean { return this._IsLoaded; }

    addListener<T extends HTMLElement, K extends keyof HTMLElementEventMap>(target: T, type: K, listener: (this: T, ev: HTMLElementEventMap[K]) => any, unload?: (target: T) => void): void
    addListener<T extends Window, K extends keyof WindowEventMap>(target: T, type: K, listener: (this: T, ev: WindowEventMap[K]) => any, unload?: (target: T) => void): void
    addListener(target: any, type: any, listener: any, unload: any): void {
        target.addEventListener(type, listener);
        this.Listeners.push([target, type, listener, unload]);
    }


    static AddItem(item: LoadManager) {
        LoadManager.Items.push(item);
    }

    private static Items: LoadManager[] = [];
}
