
export class AwaitUtil {
    public static Immidiate(): Promise<void> {
        return new Promise<void>(res => setTimeout(res, 0));
    }
    public static AnimationFrame(): Promise<void> {
        return new Promise<void>(res => requestAnimationFrame(() => res()));
    }
    public static Timeout(mill: number): Promise<void> {
        return new Promise<void>(res => setTimeout(res, mill));
    }
}

export class Awaiter<T> {
    public task: Promise<T>;

    public isDone: boolean = false;
    public hasError: boolean = false;
    public result: T;
    public reason: any;

    private resolve: (value: T) => void = null;
    private reject: (reason: any) => void = null;

    public static CreateCompleted<T>(value: T): Awaiter<T> {
        let result = new Awaiter<T>();
        result.SetResult(value);
        return result;
    }
    public static CreateFailed<T>(error: any): Awaiter<T> {
        let result = new Awaiter<T>();
        result.ThrowError(error);
        return result;
    }

    public constructor() {
        this.task = new Promise<T>(
            (resolve, reject) => {
                if (this.isDone) {
                    if (this.hasError)
                        reject(this.reason);
                    else
                        resolve(this.result);
                } else {
                    this.resolve = resolve;
                    this.reject = reject;
                }
            });
    }

    public SetResult(value: T): void {
        if (!this.isDone) {
            this.isDone = true;
            this.result = value;
            if (this.resolve)
                this.resolve(value);
        }
    }

    public ThrowError(reason: any) {
        if (!this.isDone) {
            this.isDone = true;
            this.hasError = true;
            this.reason = reason;
            if (this.reject)
                this.reject(reason);
        }
    }
}



export class AsyncXHR {

    private sended: boolean = false;

    private _headersReceived: Awaiter<number> = new Awaiter<number>();
    private _loading: Awaiter<undefined> = new Awaiter<undefined>();
    private _done: Awaiter<undefined> = new Awaiter<undefined>();

    private _xhr: XMLHttpRequest;


    public constructor() {
        this._xhr = new XMLHttpRequest();
    }

    public set responseType(value: XMLHttpRequestResponseType) {
        this._xhr.responseType = value
    }

    public get response(): any {
        return this._xhr.response;
    }
    public get statusCode(): number {
        return this._xhr.status;
    }
    public get statusText(): string {
        return this._xhr.statusText;
    }

    public send(body?: Document | XMLHttpRequestBodyInit) {
        if (this.sended)
            return;
        this.sended = true;
        this._xhr.addEventListener("readystatechange", this.ReadyStateChanged.bind(this));
        this._xhr.addEventListener("load", this.Load.bind(this))
        this._xhr.addEventListener("error", this.Error.bind(this))
        this._xhr.addEventListener("abort", this.Abort.bind(this))
        this._xhr.addEventListener("timeout", this.Timeout.bind(this));
        this._xhr.send(body)
    }

    public open(method: string, url: string | URL) {
        this._xhr.open(method, url, true);
    }

    public abort() {
        this._xhr.abort();
    }

    private ReadyStateChanged(ev: Event): any {
        switch (this._xhr.readyState) {
            case 2:
                this._headersReceived.SetResult(this._xhr.status);
                break;
            case 3:
                this._loading.SetResult(undefined);
                break;
            case 4:
                break;
            default:
        }
    }

    private Load(ev: ProgressEvent<XMLHttpRequestEventTarget>) {
        this._done.SetResult(undefined);
    }
    private Error(ev: ProgressEvent<XMLHttpRequestEventTarget>) {
        let msg = "リクエストエラー";
        this._headersReceived.ThrowError(msg);
        this._loading.ThrowError(msg);
        this._done.ThrowError(msg);
    }
    private Abort(ev: ProgressEvent<XMLHttpRequestEventTarget>) {
        let msg = "キャンセルされました";
        this._headersReceived.ThrowError(msg);
        this._loading.ThrowError(msg);
        this._done.ThrowError(msg);
    }
    private Timeout(ev: ProgressEvent<XMLHttpRequestEventTarget>) {
        let msg = "タイムアウト";
        this._headersReceived.ThrowError(msg);
        this._loading.ThrowError(msg);
        this._done.ThrowError(msg);
    }

    public HeadersReceived(): Promise<number> {
        return this._headersReceived.task;
    }
    public Loading(): Promise<undefined> {
        return this._loading.task;
    }
    public Done(): Promise<undefined> {
        return this._done.task;
    }
}

export class TimeoutException extends Error { }

export class TaskTimeout<T> {
    private _targetTask: Promise<T>;

    private _timeoutId: number;

    public readonly task: Promise<T>;

    private _done: boolean = false;

    private _resolve: (value: T) => void;

    private _reject: (reason?: any) => void;

    constructor(task: Promise<T>, ms: number) {
        this._targetTask = task;
        if (ms < 0) {
            this.task = this._targetTask;
        } else {
            this.task = new Promise<T>((resolve, reject) => {
                this._resolve = resolve;
                this._reject = reject;
            });
            task.then((value) => {
                if (!this._done) {
                    this._done = true;
                    clearTimeout(this._timeoutId);
                    this._resolve(value);
                }
            }).catch((ex) => {
                if (!this._done) {
                    this._done = true;
                    clearTimeout(this._timeoutId);
                    this._reject(ex);
                }
            });
            this._timeoutId = setTimeout(() => {
                if (!this._done) {
                    this._done = true;
                    this._reject(new TimeoutException());
                }
            }, ms);
        }
    }
}


export async function SendAsync(req: XMLHttpRequest): Promise<boolean> {
    return new Promise<boolean>((resolve, reject) => {
        req.onreadystatechange = function (e) {
            switch (req.readyState) {
                case 2://ヘッダーのダウンロード完了
                    if (req.status < 200 || 300 <= req.status)
                        reject(req.statusText);
                    break;
                case 4://中身のダウンロード完了
                    if (200 <= req.status && req.status < 300)
                        resolve(true);
                    break;
            }
            if (req.readyState === 4/*DONE*/) {
            }
        }
        req.send();
    })
}


export function AttachCanceller<T>(p: Promise<T>): [Function, Promise<[boolean, T]>] {
    var res: [Function, Promise<[boolean, T]>] = [undefined, undefined];
    res[1] = new Promise<[boolean, T]>(async (resolve, reject) => {
        res[0] = () => {
            if (resolve) {
                resolve([false, null]);
                resolve = null;
                reject = null;
            }
        }
        try {
            var r = await p;
            if (resolve) {
                resolve([true, r]);
                resolve = null;
                reject = null;
            }
        } catch (e) {
            if (reject) {
                reject(e);
                resolve = null;
                reject = null;
            }

        }
    });
    return res;
}

export function DOMEventsAsync(doc: Document): [Promise<Event>, Promise<Event>] {
    return [
        new Promise<Event>((resolve, reject) => {
            if (doc.readyState === "interactive" ||
                doc.readyState === "complete") {
                resolve(null);
            } else {
                doc.addEventListener("DOMContentLoaded", (e) => {
                    resolve(e);
                })
            }
        }),
        new Promise<Event>((resolve, reject) => {
            if (doc.readyState === "complete") {
                resolve(null);
            } else {
                window.addEventListener("load", (e) => {
                    resolve(e);
                })
            }
        })];
}

export function EventAsync(node: Node, type: string): Promise<Event> {
    console.info(`${node.nodeName}:${type}:START`);
    return new Promise<Event>((resolve, reject) => {
        var func = (e) => {
            resolve(e);
            node.removeEventListener(type, func);
            console.info(`${node.nodeName}:${type}:DONE`);
        }
        addEventListener(type, func);
    });
}

export function DoEvents(): Promise<boolean> {
    return new Promise<boolean>((resolve) => {
        setTimeout(() => resolve(true), 0);
    })
}
